exports.getSignature = function(req, res){
    var key = req.body.key;
    walkintologger.info("key received: " +key);
    var userid = req.user.id;
    s3UploadPolicy.getS3Signature(key, userid, function(err, params) {
        if (err) {
            walkintologger.error('Error generating S3 signature: ' + err);
            return res.status(500).send({ error: 'Failed to generate upload signature' });
        }
        res.send(params);
    });
}

exports.uploadToTargetS3Bucket = function(userid, batchid, filePath, callback){
    //TODO: resolve prmission issue on s3 bucket
    var key = userid + '/' + batchid + '/batchmetadata.json'
    var awsConfig = s3UploadPolicy.getS3Config(userid).postProcessing;
    var cdnUrl = awsConfig.cdnUrl;
    var s3 = new S3Client({ region: awsConfig.region });
    var stream = fs.createReadStream(filePath);
    //Metadata: {'x-amz-meta-user': userid}
    var fileData = {
                    Key: key,
                    Body: stream,
                    Bucket:awsConfig.bucket,
                    CacheControl: 'no-cache',
                    ContentType:'application/json'
                };
    // Upload.done() propagates stream errors to the rejected Promise, so no separate
    // stream.on('error') handler is needed — it would double-call callback.
    var upload = new Upload({ client: s3, params: fileData });
    upload.done().then(function(data) {
        if (stream && stream.destroy) stream.destroy();
        walkintologger.info(data);
        callback(null, data, userid, batchid, cdnUrl);
    }).catch(function(err) {
        if (stream && stream.destroy) stream.destroy();
        walkintologger.error('S3 upload error:', err);
        callback(err, null, userid, batchid, cdnUrl);
    });
}

